// Get all input items
const allItems = $input.all();

// Process each category name
const processedItems = allItems.map(item => {
  const categoryName = item.json.categoryName || "";

  // 1️⃣ Replace colon with space and capitalize first letter
  const cleanedName = categoryName.replace(/:/g, ' ');
  const capitalizedCategoryName = cleanedName.charAt(0).toUpperCase() + cleanedName.slice(1);

  // 2️⃣ Create short format (initials of each word)
  const words = cleanedName.split(' ').filter(w => w.length > 0);
  const shortFormat = words.map(w => w.charAt(0).toUpperCase()).join('');

  // Return processed item
  return {
    json: {
      categoryName: capitalizedCategoryName,
      shortFormat: shortFormat,
      originalName: categoryName // Keep original if needed
    }
  };
});

// Return all processed items
return processedItems;

