// Get the input data
const inputData = $input.all();

// Array to store all flattened items
const outputItems = [];

// Process each input item
for (const item of inputData) {
  const json = item.json;

  // Check if there's a "Split Out" field or similar nested structure
  // Adjust the field name based on your actual data structure
  const splitOutData = json['Split Out'] || json;

  // Check if there are any numeric keys (0, 1, 2, 3, ...)
  const hasNumericKeys = Object.keys(splitOutData).some(key => !isNaN(key));

  if (hasNumericKeys) {
    // If numeric keys exist, flatten them
    for (const key in splitOutData) {
      // Check if the key is a number (to handle 0, 1, 2, 3, etc.)
      if (!isNaN(key) && splitOutData[key] !== null && splitOutData[key] !== undefined) {
        // Add each nested object as a separate item
        outputItems.push({
          json: splitOutData[key]
        });
      }
    }
  } else {
    // If no numeric keys, pass through the original data
    outputItems.push({
      json: json
    });
  }
}

// Return all flattened items
return outputItems;

