        break;
      }
    }

    for (let key of allKeys) {
      if (row[key] === 'TRN No.') {
        const keyIndex = allKeys.indexOf(key);
        for (let j = keyIndex + 1; j < allKeys.length; j++) {
          if (row[allKeys[j]] && row[allKeys[j]].toString().trim() !== '') {
            trnNo = row[allKeys[j]].toString().trim();
            console.log(`✓ Found TRN No: "${trnNo}"`);
            break;
          }
        }
        break;
      }
    }

    // Extract Currency
    for (let key of allKeys) {
      const value = row[key] ? row[key].toString().trim() : '';
      if (value === 'Currency' || value === 'currency' || value === 'CURRENCY') {
        const keyIndex = allKeys.indexOf(key);
        for (let j = keyIndex + 1; j < allKeys.length; j++) {
          if (row[allKeys[j]] && row[allKeys[j]].toString().trim() !== '') {
            currency = row[allKeys[j]].toString().trim();
            console.log(`✓ Found Currency: "${currency}"`);
            break;
          }
        }
        break;
      }
    }

    // Extract Conversion
    for (let key of allKeys) {
      const value = row[key] ? row[key].toString().trim() : '';
      if (value === 'Conversion' || value === 'conversion' || value === 'CONVERSION') {
        const keyIndex = allKeys.indexOf(key);
