      }
    }

    // Extract Yacht Name
    for (let key of allKeys) {
      const value = row[key] ? row[key].toString().trim() : '';
      if (value === 'Yacht Name' || value === 'yacht name' || value === 'YACHT NAME' || value === 'Yacht') {
        const keyIndex = allKeys.indexOf(key);
        for (let j = keyIndex + 1; j < allKeys.length; j++) {
          if (row[allKeys[j]] && row[allKeys[j]].toString().trim() !== '') {
