  }

  const allKeys = Object.keys(row);
  let qtyColumn = null;
  let categoryColumn = null;
  let descColumn = null;
  let unitRateColumn = null;
  let amountColumn = null;
  let vatColumn = null;

  // First pass: Find all header columns
  for (let key of allKeys) {
    const value = row[key] ? row[key].toString().trim() : '';
    const valueUpper = value.toUpperCase();

    if (valueUpper === 'QTY' || valueUpper === 'QUANTITY') {
      qtyColumn = key;
      console.log(`Found QTY column: ${key}`);
    } else if (valueUpper === 'CATEGORY') {
      categoryColumn = key;
      console.log(`Found CATEGORY column: ${key}`);
    } else if (valueUpper === 'DESCRIPTION') {
      descColumn = key;
      console.log(`Found DESCRIPTION column: ${key}`);
    } else if (valueUpper === 'UNIT RATE' || valueUpper === 'UNITRATE') {
      unitRateColumn = key;
      console.log(`Found UNIT RATE column: ${key}`);
    } else if (valueUpper === 'AMOUNT') {
      amountColumn = key;
      console.log(`Found AMOUNT column: ${key}`);
    } else if (valueUpper === 'VAT%' || valueUpper === 'VAT %') {
      vatColumn = key;
      console.log(`Found VAT% column: ${key}`);
    }
  }

  // If Category column not found by header, find it by checking for text values between QTY and DESCRIPTION
  if (!categoryColumn && qtyColumn && descColumn) {
    const qtyIndex = allKeys.indexOf(qtyColumn);
    const descIndex = allKeys.indexOf(descColumn);

    // Look for columns between QTY and DESCRIPTION
    for (let i = qtyIndex + 1; i < descIndex; i++) {
      const key = allKeys[i];
      const value = row[key] ? row[key].toString().trim() : '';
      // Check if it contains text (not just numbers)
      if (value && isNaN(value)) {
        categoryColumn = key;
        console.log(`Found CATEGORY column by position (between QTY and DESC): ${key}`);
        break;
      }
    }
  }

  if (descColumn && qtyColumn) {
    startExtraction = true;
    if (!globalThis.columnMap) {
      globalThis.columnMap = {
        qty: qtyColumn,
        category: categoryColumn,
        description: descColumn,
        unitRate: unitRateColumn,
        amount: amountColumn,
        vat: vatColumn
      };
      console.log('✓ Header row found, column mappings:', globalThis.columnMap);
    }
    continue;
  }

  if (!startExtraction || !globalThis.columnMap) {
    continue;
  }

  const descValue = row[globalThis.columnMap.description];

  if (!descValue || descValue.toString().trim() === '') {
    continue;
  }

  const description = descValue.toString().trim();
  const qtyValue = row[globalThis.columnMap.qty];
  const categoryValue = globalThis.columnMap.category ? row[globalThis.columnMap.category] : null;
  const unitRateValue = globalThis.columnMap.unitRate ? row[globalThis.columnMap.unitRate] : null;
  const amountValue = globalThis.columnMap.amount ? row[globalThis.columnMap.amount] : null;
  const vatValue = globalThis.columnMap.vat ? row[globalThis.columnMap.vat] : null;

  let qty = null;
  if (qtyValue !== null && qtyValue !== undefined && qtyValue !== '') {
    qty = typeof qtyValue === 'number' ? qtyValue : parseFloat(qtyValue);
  }

  let category = '';
  if (categoryValue !== null && categoryValue !== undefined && categoryValue !== '') {
    category = categoryValue.toString().trim();
    // Remove colon if present
    if (category.includes(':')) {
      category = category.replace(/:/g, ' ');
      console.log(`✓ Removed colon from category: "${category}"`);
    }
  }

  let unitRate = null;
  if (unitRateValue !== null && unitRateValue !== undefined && unitRateValue !== '') {
    unitRate = typeof unitRateValue === 'number' ? unitRateValue : parseFloat(unitRateValue);
  }

  let amount = null;
  if (amountValue !== null && amountValue !== undefined && amountValue !== '') {
    amount = typeof amountValue === 'number' ? amountValue : parseFloat(amountValue);
  }

  let vatPercent = '';
  if (vatValue !== null && vatValue !== undefined && vatValue !== '') {
    const vatNum = typeof vatValue === 'number' ? vatValue : parseFloat(vatValue);
    if (!isNaN(vatNum)) {
      vatPercent = (vatNum * 100) + '%';
    }
  }

  lineItems.push({
    qty: qty !== null && !isNaN(qty) ? qty : '',
    Category: category,
    description: description,
    unitRate: unitRate !== null && !isNaN(unitRate) ? unitRate : '',
    amount: amount !== null && !isNaN(amount) ? amount : '',
    vatPercent: vatPercent
  });

  console.log(`✓ Item: QTY=${qty}, CATEGORY="${category}", DESC="${description}", RATE=${unitRate}, AMOUNT=${amount}, VAT%=${vatPercent}`);
}

