// Get current timestamp
const currentTime = new Date().toISOString();

console.log(`🕐 Check time: ${currentTime}`);

// Get items from Code5
const code5Items = $('Sheet Content Extract').first().json.items;

// Get QuickBooks items
const qbItems = $input.all();

// Extract QuickBooks item names
const qbItemNames = qbItems.map(item => {
  return (item.json.Name || item.json.name || '').toString().trim().toLowerCase();
});

console.log('QuickBooks has these items:', qbItemNames);

// Find unmatched (new) items - using Set to track unique categories
const unmatchedItems = [];
const seenCategories = new Set();

for (let item of code5Items) {
  const categoryName = (item.Category || '').toString().trim();

  if (!categoryName) continue;

  const categoryLower = categoryName.toLowerCase();

  // Skip if we've already processed this category
  if (seenCategories.has(categoryLower)) {
    continue;
  }

  // Mark this category as seen
  seenCategories.add(categoryLower);

  // Check if this category is NOT in QuickBooks
  if (!qbItemNames.includes(categoryLower)) {
    unmatchedItems.push({
      categoryName: categoryName,
      isNew: true,
      timestamp: currentTime
    });
    console.log(`✗ NOT in QuickBooks: "${categoryName}"`);
  } else {
    console.log(`✓ Already in QuickBooks: "${categoryName}"`);
  }
}

console.log(`\n📊 Total unmatched: ${unmatchedItems.length}`);

// If no new items found → return a single "false" indicator with timestamp
if (unmatchedItems.length === 0) {
  console.log('✅ No new items to create.');
  return [{
    json: {
      isNew: false,
      message: 'No new items found',
      timestamp: currentTime
    }
  }];
}

// Otherwise return the new items with timestamp
console.log(`\n🆕 Returning ${unmatchedItems.length} new items for processing`);
return unmatchedItems.map(item => ({ json: item }));

// Get ALL data from Code5
const code5Data = $('Sheet Content Extract').first().json;
// Get QuickBooks items
const qbItems = $input.all();
// Create a map of QuickBooks item names to IDs and Names
const qbItemMap = {};
qbItems.forEach(item => {
  const name = (item.json.Name || item.json.name || '').toString().trim().toLowerCase();
  const id = item.json.Id || item.json.id || '';
  const displayName = item.json.Name || item.json.name || '';
  if (name && id) {
    qbItemMap[name] = {
      id: id,
      name: displayName
    };
  }
});
console.log('QuickBooks items loaded:', Object.keys(qbItemMap).length);
// Process ALL items and add itemId + itemName where matched
const processedItems = [];
for (let item of code5Data.items) {
  const categoryName = (item.Category || '').toString().trim();

  const categoryNameLower = categoryName.toLowerCase();

  // Check if this category IS in QuickBooks
  let itemId = '';
  let itemName = '';
  let isNew = false;

  if (qbItemMap[categoryNameLower]) {
    // OLD ITEM - Found in QuickBooks
    itemId = qbItemMap[categoryNameLower].id;
    itemName = qbItemMap[categoryNameLower].name;
    isNew = false;
    console.log(`✓ MATCHED (OLD): "${categoryName}" -> ID: ${itemId}, Name: ${itemName}`);
  } else {
    // NEW ITEM - Not found in QuickBooks
    itemId = '';  // Empty for new items
    itemName = categoryName;  // Use category name as item name
    isNew = true;
    console.log(`✗ NEW ITEM: "${categoryName}" (needs to be created)`);
  }

  // Add ALL items (matched or not)
  processedItems.push({
    qty: item.qty === '' || item.qty === null || item.qty === undefined ? 0 : item.qty,
    Category: categoryName,
    itemId: itemId,      // Will be empty string if new item
    itemName: itemName,  // QuickBooks item name (or category name for new items)
    isNew: isNew,        // Flag to identify new vs old items
    description: item.description || '',
    unitRate: item.unitRate === '' || item.unitRate === null || item.unitRate === undefined ? 0 : item.unitRate,
    amount: item.amount === '' || item.amount === null || item.amount === undefined ? 0 : item.amount,
    vatPercent: item.vatPercent || ''
  });
}
console.log(`\nTotal items: ${processedItems.length}`);
console.log(`OLD items (with itemId): ${processedItems.filter(i => !i.isNew).length}`);
console.log(`NEW items (without itemId): ${processedItems.filter(i => i.isNew).length}`);
// Return ALL Code5 data with ALL items + NEW FIELDS
return [{
  json: {
    Name: code5Data.Name,
    Address: code5Data.Address,
    Emirates: code5Data.Emirates,
    trnNo: code5Data.trnNo,
    customerId: code5Data.customerId,

    // NEW FIELDS ADDED
    requestedBy: code5Data.requestedBy || '',      // Requested by
    conversion: code5Data.conversion || '',        // Conversion rate
    currency: code5Data.currency || 'AED',         // Currency code (default AED)
    yachtName: code5Data.yachtName || '',          // Yacht name
    yachtPO: code5Data.yachtPO || '',              // Yacht PO (Purchase Order)
    bankDetail: code5Data.bankDetail || '',        // Bank detail

    items: processedItems  // ALL items (old have itemId, new have isNew=true flag)
  }
}];

