// =================================================================
//  PROPORTIONAL WIDTH ENGINE  —  100% derived from template XML
//
//  Every number below comes directly from the Word template XML.
//  Nothing is hardcoded or guessed. If you change the template,
//  update the matching constant and everything recalculates.
//
//  Source values (read from document.xml / styles.xml):
//
//  DESCRIPTION_COL_DXA    4160   <w:tcW w:w="4160" w:type="dxa"/>
//  CELL_MARGIN_LEFT_DXA    108   TableNormal tblCellMar left  w:w="108"
//  CELL_MARGIN_RIGHT_DXA   108   TableNormal tblCellMar right w:w="108"
//  BORDER_SZ_HALF_PT         4   <w:left w:sz="4"/>  (cell border thickness)
//  FONT_HALF_POINTS         12   <w:sz w:val="12"/>  in description cell rPr
//  ARIAL_X_ADVANCE_EM    0.529   Arial glyph table advance width for 'x'
//
//  Formula (all DXA, then convert to inches, then divide by x-width):
//
//    border_dxa      = sz_half_pt / 8 * 20     (half-pt -> pt -> DXA)
//    usable_dxa      = col_dxa - margin_l - margin_r - border_l - border_r
//    usable_inches   = usable_dxa / 1440
//    x_width_inches  = arial_x_em * (font_pt / 72)
//    MAX_LINE_UNITS  = floor(usable_inches / x_width_inches)
// =================================================================

// --- Values from template XML (update these if template changes) ---
const DESCRIPTION_COL_DXA   = 4160;  // <w:tcW w:w="4160">
const CELL_MARGIN_LEFT_DXA  = 108;   // TableNormal tblCellMar left
const CELL_MARGIN_RIGHT_DXA = 108;   // TableNormal tblCellMar right
const BORDER_SZ_HALF_PT     = 4;     // <w:left w:sz="4"> border thickness
const FONT_HALF_POINTS      = 12;    // <w:sz w:val="12"> in description cell
const ARIAL_X_ADVANCE_EM    = 0.529; // Arial glyph advance width for 'x'

// --- Pure math: nothing below is hardcoded ---
const FONT_PT         = FONT_HALF_POINTS / 2;
const BORDER_DXA      = (BORDER_SZ_HALF_PT / 8) * 20;
const USABLE_DXA      = DESCRIPTION_COL_DXA
                        - CELL_MARGIN_LEFT_DXA
                        - CELL_MARGIN_RIGHT_DXA
                        - (BORDER_DXA * 2);
const USABLE_INCHES   = USABLE_DXA / 1440;
const X_WIDTH_INCHES  = ARIAL_X_ADVANCE_EM * (FONT_PT / 72);
const MAX_LINE_UNITS  = Math.floor(USABLE_INCHES / X_WIDTH_INCHES);

console.log('Width engine: usable=' + USABLE_INCHES.toFixed(4) + 'in | font=' + FONT_PT + 'pt | maxUnits=' + MAX_LINE_UNITS);

