/** Format a number as "1,234.56" -- returns '' for zero/null/NaN */
function formatNumber(num) {
  if (num === null || num === undefined || isNaN(num) || num === 0) return '';
  return parseFloat(num).toLocaleString('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

/**
 * DYNAMIC LINE WRAPPING (proportional width aware)
 *
 * 1. Leading/trailing blank lines are stripped (no wasted rows).
 * 2. Stray punctuation-only lines ("|", "-") are removed.
 * 3. Consecutive blank Enters collapse to ONE spacer row.
 * 4. Hard Enter -> always starts a new line.
 * 5. Width measured in proportional x-units, not raw char count.
 *    Wide chars (W,M,A) count more; narrow chars (i,l,1) count less.
 * 6. Wraps at last word boundary before MAX_LINE_UNITS is exceeded.
 */
function getWrappedLines(text) {
  if (!text) return [''];

  // ── Arial proportional glyph widths (relative to 'x' = 1.0) ──────
  // Inlined here so n8n's sandbox always has access regardless of scope.
  const CW = {
    // Uppercase
    'W':1.72,'M':1.56,'G':1.44,'O':1.44,'Q':1.44,'C':1.33,'D':1.33,
    'U':1.33,'A':1.28,'H':1.28,'N':1.28,'V':1.28,'R':1.22,'X':1.22,
    'Y':1.22,'B':1.17,'K':1.17,'P':1.17,'Z':1.17,'E':1.06,'F':1.06,
    'L':1.06,'S':1.06,'T':1.06,'J':0.72,'I':0.50,
    // Lowercase
    'w':1.44,'m':1.44,'b':1.06,'d':1.06,'g':1.06,'h':1.06,'n':1.06,
    'o':1.06,'p':1.06,'q':1.06,'u':1.06,'a':1.00,'e':1.00,'k':1.00,
    'v':1.00,'x':1.00,'y':1.00,'z':0.94,'c':0.94,'s':0.89,'t':0.67,
    'r':0.67,'f':0.56,'i':0.44,'j':0.44,'l':0.44,
    // Digits
    '0':1.11,'1':1.11,'2':1.11,'3':1.11,'4':1.11,
    '5':1.11,'6':1.11,'7':1.11,'8':1.11,'9':1.11,
    // Punctuation
    ' ':0.56,'.':0.56,',':0.56,':':0.56,';':0.56,'!':0.56,'?':1.00,
    '-':0.67,'/':0.67,'(':0.67,')':0.67,'@':1.83,'&':1.39,'%':1.56,
    '+':1.17,'=':1.17,'"':0.78,"'":0.44,'#':1.11,'$':1.11,'*':0.89,
  };
  const DW = 1.0; // default width for unmapped chars

  // Returns visual width of a string in x-units
  function calcWidth(str) {
    let w = 0;
    for (let ci = 0; ci < str.length; ci++) w += (CW[str[ci]] || DW);
    return w;
  }

  // Returns the cut index: last space before maxUnits, or hard-cut
  function calcCut(str, maxUnits) {
    let w = 0, lastSpace = -1;
    for (let ci = 0; ci < str.length; ci++) {
      w += (CW[str[ci]] || DW);
      if (str[ci] === ' ') lastSpace = ci;
      if (w > maxUnits) return lastSpace > 0 ? lastSpace : ci;
    }
    return str.length;
  }

  const hardLines = text.toString().split(/\r?\n/);
  const finalLines = [];
  const JUNK_LINE = /^[|!@#$%^&*\-_=+\\/<>]+$/;

  hardLines.forEach(function(line) {
    const trimmed = line.trim();

    // Drop junk-only lines (lone "|", stray "-", etc.)
    if (JUNK_LINE.test(trimmed)) return;

    // Blank line: collapse consecutive blanks to one
    if (trimmed.length === 0) {
      if (finalLines.length > 0 && finalLines[finalLines.length - 1] !== '') {
        finalLines.push('');
      }
      return;
    }

    // Proportional soft-wrap
    let remaining = trimmed;
    while (remaining.length > 0) {
      if (calcWidth(remaining) <= MAX_LINE_UNITS) {
        finalLines.push(remaining);
        break;
      }
      const cut = calcCut(remaining, MAX_LINE_UNITS);
      finalLines.push(remaining.substring(0, cut).trim());
      remaining = remaining.substring(cut).trim();
    }
  });

  // Strip leading and trailing blank rows
  while (finalLines.length > 0 && finalLines[0] === '') finalLines.shift();
  while (finalLines.length > 0 && finalLines[finalLines.length - 1] === '') finalLines.pop();

  return finalLines.length > 0 ? finalLines : [''];
}

//  CAPTURE HEADER / META INPUTS
// ─────────────────────────────────────────────────────────────────
const copies             = parseInt(formData[0]?.json['Copies']) || 1;
const additionalCurrency = formData[0]?.json['additionalCurrency']
                        || formData[0]?.json['additionalCurrencies'] || '';
const conversionRate     = formData[0]?.json['ConversionRate'] || null;
const requestedBy        = formData[0]?.json['Requested By'] || '';
const placeOfSupply      = formData[0]?.json['Place of Supply'] || 'UAE';

// Parse extra currencies (USD / EUR / AED)
const selectedCurrencies = [];
if (additionalCurrency) {
  additionalCurrency.toString().toUpperCase()
    .split(',').map(c => c.trim()).filter(Boolean)
    .forEach(currency => {
      if (['USD', 'EUR', 'AED'].includes(currency)) {
        selectedCurrencies.push(currency);
      }
    });
}

// ─────────────────────────────────────────────────────────────────
//  BUILD FLAT RESULTS ARRAY  (one entry per rendered row)
// ─────────────────────────────────────────────────────────────────
for (let itemIndex = 0; itemIndex < formData.length; itemIndex++) {
  const raw = formData[itemIndex].json;

  const taxCode    = raw['Tax Code']  || '';
  const taxName    = raw['Tax Name']  || '';
  const qty        = raw['QTY'];
  const unitRate   = raw['Unit Rate'];
  const amount     = raw['Amount'];
  const vatPercent = raw['VAT%'];
  const vatValue   = raw['VAT Value'];
  const totalAmt   = raw['Total Amount'];
  const description= raw['Description'] || '';

  // A row with ONLY a description (no numeric fields) = header / note row
  const isDescriptionOnly = (
    !qty && !unitRate && !amount && !vatValue && !totalAmt && description.trim() !== ''
  );

  // Format VAT%
  let formattedVatPct = '';
  if (vatPercent !== null && vatPercent !== undefined && vatPercent !== '') {
    formattedVatPct = vatPercent.toString().includes('%')
      ? vatPercent.toString()
      : `${vatPercent}%`;
  }

  const currentItem = {
    qty        : qty        || 0,
    description: description,
    unitRate   : parseFloat(unitRate)  || 0,
    amount     : parseFloat(amount)    || 0,
    vatPercent : formattedVatPct,
    vatValue   : parseFloat(vatValue)  || 0,
    totalAmount: parseFloat(totalAmt)  || 0,
    taxCode,
    taxName,
    isDescriptionOnly
  };

  for (let copy = 0; copy < copies; copy++) {
    // ── DYNAMIC WRAPPING ──────────────────────────────────────────
    //  getWrappedLines uses proportional Arial widths -- no char limit needed
    const descParts = getWrappedLines(currentItem.description);

    descParts.forEach((part, lineIndex) => {
      if (lineIndex === 0) {
        // First line carries the numeric data
        if (currentItem.isDescriptionOnly) {
          // Header / note row — no numbers
          results.push({
            qty             : '',
            description     : part,
            unitRate        : '',
            amount          : '',
            vatPercent      : '',
            vatValue        : '',
            totalAmount     : '',
            taxCode         : '',
            taxName         : '',
            isDataRow       : false,
            isDescriptionOnly: true
          });
        } else {
          // Regular line item
          results.push({
            qty             : currentItem.qty,
            description     : part,
            unitRate        : formatNumber(currentItem.unitRate),
            amount          : formatNumber(currentItem.amount),
            vatPercent      : currentItem.vatPercent,
            vatValue        : formatNumber(currentItem.vatValue),
            totalAmount     : formatNumber(currentItem.totalAmount),
            taxCode,
            taxName,
            isDataRow       : true,
            isDescriptionOnly: false
          });
        }
      } else {
        // Continuation lines — description text only, all numbers blank
        results.push({
          qty             : '',
          description     : part,
          unitRate        : '',
          amount          : '',
          vatPercent      : '',
          vatValue        : '',
          totalAmount     : '',
          taxCode         : '',
          taxName         : '',
          isDataRow       : false,
          isDescriptionOnly: currentItem.isDescriptionOnly
        });
      }
    });
  }
}

// ─────────────────────────────────────────────────────────────────
//  PAGE-BREAK  +  SUBTOTAL LOGIC
// ─────────────────────────────────────────────────────────────────

function calculatePageBreaks(items, rowsPerPage) {
  const pages = [];
  let page = [], count = 0;
  for (const item of items) {
    if (count > 0 && count + 1 > rowsPerPage) {
      pages.push(page);
      page  = [];
      count = 0;
    }
    page.push(item);
    count++;
  }
  if (page.length > 0) pages.push(page);
  return pages;
}

function calculatePageSubtotals(pageItems) {
  let amt = 0, vat = 0, total = 0;
  for (const item of pageItems) {
    if (item.isDataRow) {
      amt   += parseFloat((item.amount    || '').toString().replace(/,/g, '') || 0);
      vat   += parseFloat((item.vatValue  || '').toString().replace(/,/g, '') || 0);
      total += parseFloat((item.totalAmount|| '').toString().replace(/,/g, '')|| 0);
    }
  }
  return {
    pageAmount: formatNumber(amt),
    pageVAT   : formatNumber(vat),
    pageTotal : formatNumber(total)
  };
}

/**
 * Map page items → template placeholders.
 * startQtyNumber = 1 for page 1, 36 for page 2, 71 for page 3 …
 */
function createPageMapping(pageItems, startQtyNumber) {
  const mapping = {};
  for (let i = 0; i < MAX_ROWS_PER_PAGE; i++) {
    const n    = startQtyNumber + i;
    const item = pageItems[i];
    if (item) {
      mapping[`qty${n}`]                = item.qty;
      mapping[`description${n}`]        = item.description;
      mapping[`unitrate${n}`]           = item.unitRate;
      mapping[`amount${n}`]             = item.amount;
      mapping[`vat%${n}`]               = item.vatPercent;
      mapping[`vatvalue${n}`]           = item.vatValue;
      mapping[`totalamountvalue${n}`]   = item.totalAmount;
    } else {
      // Fill unused rows with empty strings so template placeholders are cleared
      mapping[`qty${n}`]                = '';
      mapping[`description${n}`]        = '';
      mapping[`unitrate${n}`]           = '';
      mapping[`amount${n}`]             = '';
      mapping[`vat%${n}`]               = '';
      mapping[`vatvalue${n}`]           = '';
      mapping[`totalamountvalue${n}`]   = '';
    }
  }
  const sub = calculatePageSubtotals(pageItems);
  mapping.pageSubtotalAmount = sub.pageAmount;
  mapping.pageSubtotalVAT   = sub.pageVAT;
  mapping.pageSubtotalTotal = sub.pageTotal;
  return mapping;
}

// Build pages (max 6 pages supported)
const pageBreaks  = calculatePageBreaks(results, MAX_ROWS_PER_PAGE);
const pagesNeeded = Math.min(pageBreaks.length, 6);

// Each page starts at row: 1, 36, 71, 106, 141, 176
const page1Data = pageBreaks[0] ? createPageMapping(pageBreaks[0],   1) : {};
const page2Data = pageBreaks[1] ? createPageMapping(pageBreaks[1],  36) : {};
const page3Data = pageBreaks[2] ? createPageMapping(pageBreaks[2],  71) : {};
const page4Data = pageBreaks[3] ? createPageMapping(pageBreaks[3], 106) : {};
const page5Data = pageBreaks[4] ? createPageMapping(pageBreaks[4], 141) : {};
const page6Data = pageBreaks[5] ? createPageMapping(pageBreaks[5], 176) : {};

// ─────────────────────────────────────────────────────────────────
//  GRAND TOTALS
// ─────────────────────────────────────────────────────────────────
let grandTotalAmount = 0, grandTotalVAT = 0, grandTotalFinal = 0;

pageBreaks.forEach(page => {
  const sub = calculatePageSubtotals(page);
  grandTotalAmount += parseFloat((sub.pageAmount || '').replace(/,/g, '') || 0);
  grandTotalVAT    += parseFloat((sub.pageVAT    || '').replace(/,/g, '') || 0);
  grandTotalFinal  += parseFloat((sub.pageTotal  || '').replace(/,/g, '') || 0);
});

const formattedGrandTotalAmount = formatNumber(grandTotalAmount);
const formattedGrandTotalVAT    = formatNumber(grandTotalVAT);
const formattedGrandTotalFinal  = formatNumber(grandTotalFinal);

// ─────────────────────────────────────────────────────────────────
//  VAT BREAKDOWN SUMMARY
// ─────────────────────────────────────────────────────────────────
const dataRows = results.filter(r => r.isDataRow);
let taxableAmt5 = 0, taxableAmt0 = 0, nonTaxable = 0, vat5 = 0, vat0 = 0;

dataRows.forEach(item => {
  const amt      = parseFloat((item.amount   || '').replace(/,/g, '') || 0);
  const vatVal   = parseFloat((item.vatValue || '').replace(/,/g, '') || 0);
  const tName    = item.taxName || '';
  const vatPct   = parseFloat((item.vatPercent || '').toString().replace('%', '') || 0);

  if (tName === 'Taxable Amount @ 5%' || vatPct === 5) {
    taxableAmt5 += amt;  vat5 += vatVal;
  } else if (tName === 'Taxable Amount @ 0%') {
    taxableAmt0 += amt;  vat0 += vatVal;
  } else if (tName === 'Non Taxable Amount') {
    nonTaxable  += amt;
  } else {
    if      (vatPct === 5) { taxableAmt5 += amt;  vat5 += vatVal; }
    else if (vatPct === 0) { taxableAmt0 += amt;  vat0 += vatVal; }
    else                   { nonTaxable  += amt; }
  }
});

const invoiceSummary = {
  taxableAmount5Percent: formatNumber(taxableAmt5),
  taxableAmount0Percent: formatNumber(taxableAmt0),
  nonTaxableAmount      : formatNumber(nonTaxable),
  vat5Percent           : formatNumber(vat5),
  vat0Percent           : formatNumber(vat0),
  totalAmountAED        : formattedGrandTotalFinal
};

// ─────────────────────────────────────────────────────────────────
//  PER-PAGE FINAL DATA  (subtotals on every page, grand total on last page only)
// ─────────────────────────────────────────────────────────────────
const allPageData = [page1Data, page2Data, page3Data, page4Data, page5Data, page6Data];
const finalPages  = {};

for (let i = 0; i < pagesNeeded; i++) {
  const pageNum        = i + 1;
  const currentPgData  = allPageData[i];
  const isLastPage     = (pageNum === pagesNeeded);

  finalPages[`page${pageNum}`] = {
    ...currentPgData,
    subtotal: {
      amount: currentPgData.pageSubtotalAmount || '',
      vat   : currentPgData.pageSubtotalVAT    || '',
      total : currentPgData.pageSubtotalTotal  || ''
    },
    grandTotal: {
      amount: isLastPage ? formattedGrandTotalAmount : '',
      vat   : isLastPage ? formattedGrandTotalVAT    : '',
      total : isLastPage ? formattedGrandTotalFinal  : ''
    },
    showVATBreakdown: isLastPage
  };
}

// ─────────────────────────────────────────────────────────────────
//  CURRENCY FLAGS
// ─────────────────────────────────────────────────────────────────
const currencyused      = formData[0]?.json['currencyused'] || 'AED';
const currency          = formData[0]?.json['Currency']     || 'AED';
const homeBalanceAED    = formData[0]?.json['HomeBalance (AED)'] || null;
const needUSDConversion = selectedCurrencies.includes('USD') && currencyused !== 'USD';
const needEURConversion = selectedCurrencies.includes('EUR') && currencyused !== 'EUR';

// ─────────────────────────────────────────────────────────────────
//  FINAL RETURN OBJECT
// ─────────────────────────────────────────────────────────────────
const baseReturnObject = {
  // ── Currency / meta ──────────────────────────────────────────
  additionalCurrency,
  selectedCurrencies,
  needUSDConversion,
  needEURConversion,
  currencyused,
  ConversionRate: conversionRate,
  Currency: currency,
  ...(homeBalanceAED !== null && { 'HomeBalance (AED)': homeBalanceAED }),

  // ── Row data ─────────────────────────────────────────────────
  items         : results,
  itemCount     : dataRows.length,
  totalRowsNeeded: results.length,
  templatePageNumber: pagesNeeded,

  // ── Totals (multiple aliases for template compatibility) ──────
  totalAmount   : formatNumber(grandTotalAmount),
  totalVAT      : formatNumber(grandTotalVAT),
  grandTotal    : formattedGrandTotalFinal,

  totals: {
    totalAmount   : formatNumber(grandTotalAmount),
    totalVAT      : formatNumber(grandTotalVAT),
    grandTotal    : formattedGrandTotalFinal,
    allgrandtotalamount: formattedGrandTotalAmount,
    allgrandtotalvat   : formattedGrandTotalVAT,
    allgrandtotaltotal : formattedGrandTotalFinal
  },

  allgrandtotalamount: formattedGrandTotalAmount,
  allgrandtotalvat   : formattedGrandTotalVAT,
  allgrandtotaltotal : formattedGrandTotalFinal,

  grandTotals: {
    amount: formattedGrandTotalAmount,
    vat   : formattedGrandTotalVAT,
    total : formattedGrandTotalFinal
  },

  grandTotalAmount: formattedGrandTotalAmount,
  grandTotalVAT   : formattedGrandTotalVAT,
  grandTotalFinal : formattedGrandTotalFinal,

  // ── VAT summary (template placeholders) ──────────────────────
  invoiceSummary,
  vatBreakdown: {
    taxableAmount5Percent: invoiceSummary.taxableAmount5Percent,
    taxableAmount0Percent: invoiceSummary.taxableAmount0Percent,
    nonTaxableAmount      : invoiceSummary.nonTaxableAmount,
    vat5Percent           : invoiceSummary.vat5Percent,
    vat0Percent           : invoiceSummary.vat0Percent,
    totalAmountAED        : invoiceSummary.totalAmountAED
  },

  // Direct template placeholder aliases
  '5%value'         : invoiceSummary.taxableAmount5Percent,
  '0%value'         : invoiceSummary.taxableAmount0Percent,
  'nontaxablevalue' : invoiceSummary.nonTaxableAmount,
  '5%vatvalue'      : invoiceSummary.vat5Percent,
  'totalamountfinal': invoiceSummary.totalAmountAED,
  allPagesGrandTotal: formattedGrandTotalFinal,

  // ── Per-page data ─────────────────────────────────────────────
  page1: finalPages.page1 || {},
  page2: finalPages.page2 || {},
  page3: finalPages.page3 || {},
  page4: finalPages.page4 || {},
  page5: finalPages.page5 || {},
  page6: finalPages.page6 || {},

  // Raw page data (flat, for direct template injection)
  page1Data, page2Data, page3Data, page4Data, page5Data, page6Data,

  // ── Customer / header info ────────────────────────────────────
  customerInfo: {
    name      : formData[0]?.json['Name']       || 'Sample Customer',
    address   : formData[0]?.json['Address']    || '',
    emirates  : formData[0]?.json['Emirates']   || 'Dubai',
    invoiceNo : formData[0]?.json['Invoice No'] || 'INV-001',
    docNumber : formData[0]?.json['DocNumber']  || formData[0]?.json['Invoice No'] || 'INV-001',
    DocId     : formData[0]?.json['INV-Id']     || formData[0]?.json['Invoice No'] || 'INV-001',
    trnNo     : formData[0]?.json['TRN No']     || '',
    Id        : formData[0]?.json['Id']         || ''
  },

  yachtName  : formData[0]?.json['YachtName']   || formData[0]?.json['yachtName'] || '',
  yachtPO    : formData[0]?.json['YachtPO']     || formData[0]?.json['yachtPO']   || '',
  bankDetail : formData[0]?.json['Bank Detail'] || '',
  invoiceDate: formData[0]?.json['Date']        || new Date().toLocaleDateString('en-GB'),
};

// placeOfSupply / requestedBy
if (requestedBy) {
  baseReturnObject['placeofsupply'] = requestedBy;
}

return [{ json: baseReturnObject }];

// Get all input data
const inputData = $input.all();
// Map for currency symbols
const currencySignMap = {
  USD: '$',
  EUR: '€',
};
for (const item of inputData) {
  // -------------------------------
  // 📅 Invoice Date Formatting
  // -------------------------------
  const invoiceDateRaw = item.json.invoiceDate;

  if (invoiceDateRaw) {
    // Parse the date (assuming format is DD/MM/YYYY or similar)
    let dateObj;

    if (invoiceDateRaw.includes('/')) {
      const parts = invoiceDateRaw.split('/');
      // Assuming DD/MM/YYYY format
      dateObj = new Date(parts[2], parts[1] - 1, parts[0]);
    } else {
      dateObj = new Date(invoiceDateRaw);
    }

    // Format to "Month Day, Year"
    const options = { year: 'numeric', month: 'long', day: 'numeric' };
    const formattedDate = dateObj.toLocaleDateString('en-US', options);
    item.json.invoiceDate = formattedDate;
  }

  // -------------------------------
  // 🏦 Dynamic Bank Details
  // -------------------------------
  const bankDetail = item.json.bankDetail || ''; // e.g., "AED TO USD"

  const bankMap = {
    USD: {
      bankName: 'Emirates NBD – Tecom Branch, Dubai, UAE',
      accountNumber: '102-48474993-02',
      iban: 'AE32 0260 0010 2484 7499 302'
    },
    EUR: {
      bankName: 'Emirates NBD – Barsha Heights (TECOM), Dubai',
      accountNumber: '102-48474993-03',
      iban: 'AE05 0260 0010 2484 7499 303'
    },
    AED: {
      bankName: 'EMIRATES NBD – TECOM BRANCH, DUBAI UAE',
      accountNumber: '101-48474993-01',
      iban: 'AE24 0260 0010 1484 7499 301'
    }
  };

  // -------------------------------
  // Determine bank key and target currency
  // -------------------------------
  const bankDetailUpper = String(bankDetail).toUpperCase().trim();
  let bankKey = '';
  let targetCurrency = '';

  if (bankDetailUpper.includes('USD')) {
    targetCurrency = 'USD';
  } else if (bankDetailUpper.includes('EUR') || bankDetailUpper.includes('EURO')) {
    targetCurrency = 'EUR';
  }

  if (bankDetailUpper.includes('USD') && bankDetailUpper.includes('AED')) {
    bankKey = 'AED'; // AED account used, converted to USD
  } else if (bankDetailUpper.includes('EUR') && bankDetailUpper.includes('AED')) {
    bankKey = 'AED'; // AED account used, converted to EUR
  } else if (bankDetailUpper.includes('USD')) {
    bankKey = 'USD';
  } else if (bankDetailUpper.includes('EUR') || bankDetailUpper.includes('EURO')) {
    bankKey = 'EUR';
  } else if (bankDetailUpper.includes('AED')) {
    bankKey = 'AED';
  }

  const selectedBank = bankMap[bankKey] || {};
  item.json.bankName = selectedBank.bankName || '';
  item.json.accountNumber = selectedBank.accountNumber || '';
  item.json.iban = selectedBank.iban || '';

  // -------------------------------
  // 🔢 Division Logic
  // -------------------------------
  const conversionRateRaw = item.json.ConversionRate;
  const grandTotalFinalRaw = item.json.grandTotalFinal;

  if (conversionRateRaw != null && grandTotalFinalRaw != null) {
    const conversionRate = Number(String(conversionRateRaw).replace(/[^0-9.-]/g, ''));
    const grandTotalFinal = Number(String(grandTotalFinalRaw).replace(/[^0-9.-]/g, ''));

    if (!isNaN(conversionRate) && !isNaN(grandTotalFinal) && conversionRate !== 0) {
      const result = grandTotalFinal / conversionRate;
      item.json.dividedResult = result.toLocaleString('en-US', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
      });
    } else {
      item.json.dividedResult = 'Error: Invalid number';
    }
  } else {
    item.json.dividedResult = 'Error: Missing data';
  }

  // -------------------------------
  // 💱 Set currency and sign based on Currency field
  // -------------------------------
  const currencyField = (item.json.Currency || '').toUpperCase().trim();
  let finalCurrency = '';

  // Check if it's a conversion format like "AED TO USD" or "AED TO EUR"
  if (currencyField.includes('TO')) {
    if (currencyField.includes('USD')) {
      finalCurrency = 'USD';
    } else if (currencyField.includes('EUR') || currencyField.includes('EURO')) {
      finalCurrency = 'EUR';
    } else if (currencyField.includes('AED')) {
      finalCurrency = 'AED';
    }
  } else {
    // Direct currency like "USD", "EUR", "AED"
    finalCurrency = currencyField;
  }

  item.json.sameCurrency = finalCurrency;
  item.json.currencySign = currencySignMap[finalCurrency] || '';
}
return inputData;

// Get the AED amount from the "Code" node
const aedAmountRaw = $('Code_').first().json.totalamountfinal;

// Remove commas and convert to number
const aedAmount = parseFloat(aedAmountRaw.toString().replace(/,/g, ''));

// Get exchange rates from HTTP Request
const rates = $json.conversion_rates;

// Convert AED to USD and EUR
const usdAmount = aedAmount * rates.USD;
const eurAmount = aedAmount * rates.EUR;

// Helper to format number with commas and 2 decimals
function formatCurrency(num) {
  return num.toLocaleString('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

return {
  AED: formatCurrency(aedAmount),
  USD: formatCurrency(usdAmount),
  EUR: formatCurrency(eurAmount),
  exchange_rate_USD: rates.USD,
  exchange_rate_EUR: rates.EUR
};

